+//! vc_config - Configuration parsing and validation for Vibe Cockpit
+//!
+//! This crate provides:
+//! - TOML configuration parsing
+//! - Default value handling
+//! - Environment variable overrides
+//! - Path expansion (~/ to home directory)
+//! - Auto-discovery from standard config paths
+//! - Machine inventory definitions
+
+use serde::{Deserialize, Serialize};
+use std::collections::HashMap;
+use std::path::{Path, PathBuf};
+use std::time::Duration;
+use thiserror::Error;
+use tracing::info;
+
+/// Configuration errors
+#[derive(Error, Debug)]
+pub enum ConfigError {
+    #[error("Failed to read config file: {0}")]
+    ReadError(#[from] std::io::Error),
+
+    #[error("Failed to parse TOML: {0}")]
+    ParseError(#[from] toml::de::Error),
+
+    #[error("Invalid configuration: {0}")]
+    ValidationError(String),
+
+    #[error("Missing required field: {0}")]
+    MissingField(String),
+}
+
+/// Top-level configuration structure
+#[derive(Debug, Clone, Serialize, Deserialize)]
+#[serde(default)]
+pub struct VcConfig {
+    /// Global settings
+    pub global: GlobalConfig,
+
+    /// Machine inventory
+    pub machines: HashMap<String, MachineConfig>,
+
+    /// Collector settings
+    pub collectors: CollectorConfig,
+
+    /// Alert settings
+    pub alerts: AlertConfig,
+
+    /// Autopilot settings
+    pub autopilot: AutopilotConfig,
+
+    /// TUI settings
+    pub tui: TuiConfig,
+
+    /// Web dashboard settings
+    pub web: WebConfig,
+}
+
+impl Default for VcConfig {
+    fn default() -> Self {
+        Self {
+            global: GlobalConfig::default(),
+            machines: HashMap::new(),
+            collectors: CollectorConfig::default(),
+            alerts: AlertConfig::default(),
+            autopilot: AutopilotConfig::default(),
+            tui: TuiConfig::default(),
+            web: WebConfig::default(),
+        }
+    }
+}
+
+/// Global configuration settings
+#[derive(Debug, Clone, Serialize, Deserialize)]
+#[serde(default)]
+pub struct GlobalConfig {
+    /// Path to DuckDB database file
+    pub db_path: PathBuf,
+
+    /// Default poll interval in seconds
+    pub poll_interval_secs: u64,
+
+    /// Log level (trace, debug, info, warn, error)
+    pub log_level: String,
+
+    /// Enable JSON logging
+    pub json_logs: bool,
+}
+
+impl Default for GlobalConfig {
+    fn default() -> Self {
+        Self {
+            db_path: default_db_path(),
+            poll_interval_secs: 120,
+            log_level: "info".to_string(),
+            json_logs: false,
+        }
+    }
+}
+
+/// Default database path using XDG directories
+fn default_db_path() -> PathBuf {
+    dirs::data_local_dir()
+        .unwrap_or_else(|| PathBuf::from("."))
+        .join("vc")
+        .join("vc.duckdb")
+}
+
+/// Expand tilde in path to home directory
+pub fn expand_path(path: &Path) -> PathBuf {
+    let path_str = path.to_string_lossy();
+    if path_str.starts_with("~/") {
+        if let Some(home) = dirs::home_dir() {
+            return home.join(&path_str[2..]);
+        }
+    } else if path_str == "~" {
+        if let Some(home) = dirs::home_dir() {
+            return home;
+        }
+    }
+    path.to_path_buf()
+}
+
+/// Expand all paths in GlobalConfig
+impl GlobalConfig {
+    pub fn expand_paths(&mut self) {
+        self.db_path = expand_path(&self.db_path);
+    }
+}
+
+/// Machine configuration
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct MachineConfig {
+    /// Display name
+    pub name: String,
+
+    /// SSH hostname (if remote)
+    pub ssh_host: Option<String>,
+
+    /// SSH user (if remote)
+    pub ssh_user: Option<String>,
+
+    /// SSH key path (if remote)
+    pub ssh_key: Option<PathBuf>,
+
+    /// Whether this machine is enabled
+    #[serde(default = "default_true")]
+    pub enabled: bool,
+
+    /// Machine-specific collector overrides
+    #[serde(default)]
